// app/ClientLayout.js - ✅ AGGIORNATO: WhatsAppPopup + Sessioni attive + sessionService ping
// ✅ FIX 04/03/2026: Rimossa dipendenza 'user' da useEffect sessionService (causava restart inutili)
// ✅ ADD 06/03/2026: Integrazione WhatsAppPopup (messaggio in arrivo da bot VPS via Pusher)
'use client';

import { useState, useEffect, useMemo } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { useAuth } from '@/contexts/AuthContext';
import {
  Box,
  Drawer,
  AppBar,
  Toolbar,
  List,
  Typography,
  IconButton,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Badge,
  Button,
  Chip,
  Divider,
  Tooltip
} from '@mui/material';
import {
  Circle,
  Menu as MenuIcon,
  Logout as LogoutIcon,
  Dashboard as DashboardIcon,
  ShoppingCart as OrdiniIcon,
  People as ClientiIcon,
  Inventory as MagazzinoIcon,
  Label as EtichetteIcon,
  BarChart as ReportIcon,
  CalendarMonth as CalendarioIcon,
  Phone as ChiamateIcon,
  Receipt as FatturazioneIcon,
  FileDownload as ImportFattureIcon,
  Thermostat as HaccpIcon,
  Euro as CorrispettiviIcon,
  ShowChart as GraficiIcon,
  Computer as SessioniIcon,
  Lock as ChiusureIcon,
  Person as UtentiIcon,
  Settings as ImpostazioniIcon,
  ExitToApp as EsciIcon,
} from '@mui/icons-material';
import { alpha } from '@mui/material/styles';
import { BRAND } from '@/theme/theme';
import useIncomingCall from '@/hooks/useIncomingCall';
import useWhatsAppMessage from '@/hooks/useWhatsAppMessage';
import CallPopup from '@/components/CallPopup';
import WhatsAppPopup from '@/components/WhatsAppPopup';
import NotificaFatture from '@/components/NotificaFatture';
import dispositivoService from '@/services/dispositivoService';
import sessionService from '@/services/sessionService';
import CacheService from '@/services/cacheService';
import NotificationCenter from '@/components/alerts/NotificationCenter';
import PushPromptBanner from '@/components/PushPromptBanner';
import firebasePushService from '@/services/firebasePushService';

const drawerWidth = 248;

// Logo Pastificio Nonna Claudia — embedded base64
const LOGO_SIDEBAR = 'data:image/jpeg;base64,';
const LOGO_MINI    = 'data:image/jpeg;base64,';

const allMenuItems = [
  { id: 'dashboard',      title: 'Dashboard',            icon: <DashboardIcon />,     iconColor: '#42A5F5', path: '/dashboard',      roles: ['admin', 'operatore', 'visualizzatore'] },
  { id: 'ordini',         title: 'Ordini',               icon: <OrdiniIcon />,         iconColor: '#66BB6A', path: '/',               roles: ['admin', 'operatore', 'visualizzatore'] },
  { id: 'clienti',        title: 'Clienti',              icon: <ClientiIcon />,        iconColor: '#AB47BC', path: '/clienti',        roles: ['admin', 'operatore', 'visualizzatore'] },
  { id: 'magazzino',      title: 'Magazzino',            icon: <MagazzinoIcon />,      iconColor: '#FF7043', path: '/magazzino',      roles: ['admin', 'operatore'] },
  { id: 'etichette',      title: 'Etichette',            icon: <EtichetteIcon />,      iconColor: '#26C6DA', path: '/etichette',      roles: ['admin', 'operatore'] },
  { id: 'report',         title: 'Report',               icon: <ReportIcon />,         iconColor: '#C8A830', path: '/report',         roles: ['admin', 'operatore'] },
  { id: 'calendario',     title: 'Calendario',           icon: <CalendarioIcon />,     iconColor: '#EC407A', path: '/calendario',     roles: ['admin', 'operatore', 'visualizzatore'] },
  { id: 'chiamate',       title: 'Chiamate',             icon: <ChiamateIcon />,       iconColor: '#29B6F6', path: '/chiamate',       roles: ['admin', 'operatore'] },
  { id: 'fatturazione',   title: 'Fatturazione',         icon: <FatturazioneIcon />,   iconColor: '#FFA726', path: '/fatturazione',   roles: ['admin'] },
  { id: 'import-fatture', title: 'Import Fatture',       icon: <ImportFattureIcon />,  iconColor: '#78909C', path: '/import-fatture', roles: ['admin'] },
  { id: 'haccp',          title: 'HACCP',                icon: <HaccpIcon />,          iconColor: '#EF5350', path: '/haccp',          roles: ['admin', 'operatore'] },
  { id: 'corrispettivi',  title: 'Corrispettivi',        icon: <CorrispettiviIcon />,  iconColor: '#C8A830', path: '/corrispettivi',  roles: ['admin'] },
  { id: 'grafici',        title: 'Grafici Corrispettivi',icon: <GraficiIcon />,        iconColor: '#26A69A', path: '/grafici',        roles: ['admin'] },
  { id: 'sessioni',       title: 'Sessioni Attive',      icon: <SessioniIcon />,       iconColor: '#5C6BC0', path: '/sessioni',       roles: ['admin', 'operatore'] },
  { id: 'chiusure',       title: 'Calendario Chiusure',  icon: <ChiusureIcon />,       iconColor: '#EF5350', path: '/chiusure',       roles: ['admin', 'operatore', 'visualizzatore'] },
  { id: 'utenti',         title: 'Gestione Utenti',      icon: <UtentiIcon />,         iconColor: '#8D6E63', path: '/utenti',         roles: ['admin'] },
  { id: 'impostazioni',   title: 'Impostazioni',         icon: <ImpostazioniIcon />,   iconColor: '#90A4AE', path: '/impostazioni',   roles: ['admin'] }
];

const roleColors = {
  admin: { bg: '#dc2626', text: 'white', label: 'Admin' },
  operatore: { bg: '#2563eb', text: 'white', label: 'Operatore' },
  visualizzatore: { bg: '#6b7280', text: 'white', label: 'Visualizzatore' }
};

export default function ClientLayout({ children }) {
  const router = useRouter();
  const pathname = usePathname();
  const { user, logout, isAdmin } = useAuth();
  const [mobileOpen, setMobileOpen] = useState(false);
  const [mounted, setMounted] = useState(false);

  const { chiamataCorrente, clearChiamata, connected, pusherService } = useIncomingCall();
  const { messaggioCorrente, isPopupOpen: isWhatsAppPopupOpen, handleClosePopup: closeWhatsAppPopup } = useWhatsAppMessage();

  useEffect(() => {
    setMounted(true);
  }, []);

  // Pulizia automatica cache localStorage all'avvio
  useEffect(() => {
    if (!mounted || typeof window === 'undefined') return;
    CacheService.inizializza();
  }, [mounted]);

  // ✅ FIX 04/03/2026: Rimossa dipendenza 'user' - causava stop/restart continui del sessionService
  // Il sessionService usa il token da localStorage, non ha bisogno dell'oggetto user
  useEffect(() => {
    if (!mounted || typeof window === 'undefined') return;
    
    const token = localStorage.getItem('token');
    if (token) {
      sessionService.inizializza();
    }

    return () => {
      sessionService.ferma();
    };
  }, [mounted]); // ✅ Era [mounted, user] - 'user' causava re-init ad ogni render

  // INIZIALIZZAZIONE PUSHER
  useEffect(() => {
    if (!mounted || typeof window === 'undefined') return;

    const timer = setTimeout(() => {
      if (pusherService) {
        const status = pusherService.getStatus();
        if (!status.connected && !status.initialized) {
          pusherService.initialize().catch(err => {
            console.error('[CLIENT LAYOUT] Errore init Pusher:', err);
          });
        }
      }
    }, 500);

    return () => clearTimeout(timer);
  }, [mounted, pusherService]);

  // Inizializza Web Push Notifications
  useEffect(() => {
    if (!mounted || typeof window === 'undefined') return;
    firebasePushService.inizializza().catch(err => {
      console.warn('[PUSH] Init warning:', err.message);
    });
  }, [mounted]);

  // Ascolta click su notifica push
  useEffect(() => {
    if (!mounted || typeof window === 'undefined') return;

    const handlePushClick = (event) => {
      const data = event.detail;
      if (!data) return;
      
      switch (data.action || data.tipo) {
        case 'chiamata':
          break;
        case 'ordine':
          if (data.ordineId) {
            router.push('/?ordine=' + data.ordineId);
          }
          break;
        case 'alert':
          router.push('/?action=alert');
          break;
      }
    };

    window.addEventListener('push-notification-click', handlePushClick);
    return () => window.removeEventListener('push-notification-click', handlePushClick);
  }, [mounted, router]);

  // Menu filtrato per ruolo utente
  const menuItems = useMemo(() => {
    if (!user) return [];
    return allMenuItems.filter(item => item.roles.includes(user.role));
  }, [user]);

  const handleDrawerToggle = () => setMobileOpen(!mobileOpen);

  const handleNavigation = (path) => {
    router.push(path);
    setMobileOpen(false);
  };

  const handleLogout = () => {
    sessionService.ferma();
    logout();
  };

  const isSelected = (path) => {
    if (path === '/') return pathname === '/';
    return pathname === path || pathname.startsWith(path + '/');
  };

  const handleSaveNote = async (callId, note) => {
    try {
      const token = localStorage.getItem('token');
      const API_URL = process.env.NEXT_PUBLIC_API_URL || 'https://pastificio-completo-production.up.railway.app/api';

      const responseHistory = await fetch(
        `${API_URL}/chiamate/history?limit=100`,
        { headers: { 'Authorization': `Bearer ${token}` } }
      );

      if (responseHistory.ok) {
        const data = await responseHistory.json();
        const chiamata = data.chiamate?.find(c => c.callId === callId);

        if (chiamata) {
          await fetch(
            `${API_URL}/chiamate/${chiamata._id}`,
            {
              method: 'PUT',
              headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
              },
              body: JSON.stringify({ note })
            }
          );
        }
      }
      clearChiamata();
    } catch (error) {
      console.error('[CLIENT LAYOUT] Errore salvataggio nota:', error);
    }
  };

  const roleInfo = roleColors[user?.role] || roleColors.operatore;

  const drawer = (
    <Box>
      {/* ✅ Header sidebar brand */}
      <Box sx={{
        px: 2, py: 2,
        background: 'linear-gradient(160deg, #111 0%, #1C1C1E 100%)',
        borderBottom: `2px solid ${BRAND.gold}`,
        textAlign: 'center',
      }}>
        {/* Logo — contenitore proporzionato 3:2 come il logo ovale reale */}
        <Box sx={{
          width: 132, height: 86,
          borderRadius: '50%',
          overflow: 'hidden',
          border: `2px solid ${BRAND.gold}`,
          boxShadow: `0 0 0 3px ${alpha(BRAND.gold, 0.20)}, 0 4px 12px rgba(0,0,0,0.40)`,
          bgcolor: 'white', mx: 'auto', mb: 1,
        }}>
          <img
            src={LOGO_SIDEBAR}
            alt="Pastificio Nonna Claudia"
            style={{ width: '100%', height: '100%', objectFit: 'fill' }}
          />
        </Box>
        <Typography sx={{ color: 'white', fontWeight: 700, fontSize: '0.76rem', lineHeight: 1.3, letterSpacing: '0.02em' }}>
          Pastificio<br />Nonna Claudia
        </Typography>
        {user && (
          <Box sx={{ mt: 1.5, pt: 1, borderTop: `1px solid ${alpha(BRAND.gold, 0.25)}`, display: 'flex', alignItems: 'center', gap: 1, justifyContent: 'center' }}>
            <Typography sx={{ color: 'rgba(255,255,255,0.85)', fontSize: '0.75rem', fontWeight: 600 }}>
              {user.nome}
            </Typography>
            <Chip label={roleInfo.label} size="small"
              sx={{ height: 18, fontSize: '0.60rem', fontWeight: 700,
                    bgcolor: alpha('#fff', 0.12), color: 'rgba(255,255,255,0.90)',
                    border: `1px solid ${alpha('#fff', 0.20)}` }} />
          </Box>
        )}
      </Box>

      <List>
        {menuItems.map((item) => (
          <ListItemButton
            key={item.id}
            onClick={() => handleNavigation(item.path)}
            selected={isSelected(item.path)}
            sx={{
              color: isSelected(item.path) ? BRAND.goldLight : 'rgba(255,255,255,0.72)',
              bgcolor: isSelected(item.path) ? alpha(BRAND.gold, 0.18) : 'transparent',
              borderLeft: isSelected(item.path) ? `3px solid ${BRAND.gold}` : '3px solid transparent',
              borderRadius: '0 8px 8px 0',
              mr: 1, py: 0.9,
              transition: 'all 0.15s ease',
              '&:hover': { bgcolor: 'rgba(255,255,255,0.07)', color: 'white' },
            }}
          >
            <Box sx={{
              width: 34, height: 34, borderRadius: 1.5, mr: 1.5, flexShrink: 0,
              bgcolor: isSelected(item.path)
                ? `${item.iconColor}33`
                : `${item.iconColor}1A`,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              transition: 'all 0.15s ease',
              '& .MuiSvgIcon-root': {
                fontSize: '1.1rem',
                color: item.iconColor,
                opacity: isSelected(item.path) ? 1 : 0.8,
              },
            }}>
              {item.icon}
            </Box>
            <ListItemText primary={item.title} primaryTypographyProps={{
              fontSize: '0.84rem',
              fontWeight: isSelected(item.path) ? 700 : 400,
              color: isSelected(item.path) ? 'white' : 'rgba(255,255,255,0.78)',
            }} />
          </ListItemButton>
        ))}
      </List>

      <Divider />
      <List>
        <ListItemButton onClick={handleLogout} sx={{
          color: 'rgba(255,100,100,0.85)', mr: 1, borderRadius: '0 8px 8px 0',
          '&:hover': { bgcolor: 'rgba(255,50,50,0.12)', color: '#ff6b6b' },
        }}>
          <ListItemIcon sx={{ color: 'inherit', minWidth: 40, '& .MuiSvgIcon-root': { fontSize: '1.25rem' } }}>
            <EsciIcon sx={{ color: '#EF9A9A' }} />
          </ListItemIcon>
          <ListItemText primary="Esci" primaryTypographyProps={{ fontSize: '0.84rem', fontWeight: 500 }} />
        </ListItemButton>
      </List>
    </Box>
  );

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" elevation={0} sx={{
          width: { sm: `calc(100% - ${drawerWidth}px)` },
          ml: { sm: `${drawerWidth}px` },
        }}>
        <Toolbar>
          {/* Hamburger mobile */}
          <IconButton color="inherit" edge="start" onClick={handleDrawerToggle}
            sx={{ mr: 1, display: { sm: 'none' } }}>
            <MenuIcon />
          </IconButton>

          {/* Logo mini solo mobile */}
          <Box sx={{ display: { xs: 'flex', sm: 'none' }, mr: 1,
            width: 36, height: 28, borderRadius: '6px', overflow: 'hidden',
            border: `1.5px solid ${BRAND.gold}`, bgcolor: 'white',
            alignItems: 'center', justifyContent: 'center' }}>
            <img src={LOGO_MINI} alt="Logo" style={{ width: '100%', height: '100%', objectFit: 'contain' }} />
          </Box>

          <Typography variant="h6" noWrap sx={{ flexGrow: 1, fontWeight: 700, fontSize: { xs: '1rem', sm: '1.1rem' } }}>
            {menuItems.find(item => isSelected(item.path))?.title || 'Gestione Ordini'}
          </Typography>

          {/* Badge LIVE/OFFLINE */}
          {mounted && (
            <Box sx={{
              display: { xs: 'none', md: 'flex' }, alignItems: 'center', gap: 0.5,
              px: 1.5, py: 0.4, borderRadius: 2, mr: 1,
              bgcolor: alpha(connected ? '#4CAF50' : '#F44336', 0.20),
              border: `1px solid ${alpha(connected ? '#4CAF50' : '#F44336', 0.50)}`,
              fontSize: '0.72rem', fontWeight: 700, color: 'white',
            }}>
              <Circle sx={{ fontSize: 8, color: connected ? '#4CAF50' : '#F44336' }} />
              {connected ? 'LIVE' : 'OFFLINE'}
            </Box>
          )}

          {/* Chip utente */}
          {user && (
            <Chip
              label={user.nome}
              size="small"
              sx={{
                display: { xs: 'none', sm: 'flex' },
                mr: 1, bgcolor: alpha('#fff', 0.18), color: 'white',
                fontWeight: 600, fontSize: '0.8rem',
                border: `1px solid ${alpha('#fff', 0.30)}`,
              }}
            />
          )}

          <NotificationCenter pusherService={pusherService} />

          <Tooltip title="Esci">
            <IconButton color="inherit" onClick={handleLogout}>
              <LogoutIcon />
            </IconButton>
          </Tooltip>
        </Toolbar>
      </AppBar>
      
      <Box
        component="nav"
        sx={{ width: { sm: drawerWidth }, flexShrink: { sm: 0 } }}
      >
        <Drawer
          variant="temporary"
          open={mobileOpen}
          onClose={handleDrawerToggle}
          ModalProps={{ keepMounted: true }}
          sx={{
            display: { xs: 'block', sm: 'none' },
            '& .MuiDrawer-paper': { boxSizing: 'border-box', width: drawerWidth, bgcolor: '#1C1C1E' }
          }}
        >
          {drawer}
        </Drawer>
        
        <Drawer
          variant="permanent"
          sx={{
            display: { xs: 'none', sm: 'block' },
            '& .MuiDrawer-paper': { boxSizing: 'border-box', width: drawerWidth, bgcolor: '#1C1C1E' }
          }}
          open
        >
          {drawer}
        </Drawer>
      </Box>
      
      <Box
        component="main"
        sx={{
          flexGrow: 1,
          width: { sm: `calc(100% - ${drawerWidth}px)` },
          minHeight: '100vh',
          mt: { xs: '56px', sm: '64px' },
          bgcolor: 'background.default',
        }}
      >
        {children}
      </Box>

      {mounted && chiamataCorrente && dispositivoService.isNotificaAbilitata('chiamate3cx') && (
        <CallPopup
          chiamata={chiamataCorrente}
          onClose={clearChiamata}
          onSaveNote={handleSaveNote}
        />
      )}

      {mounted && <NotificaFatture />}

      {mounted && <PushPromptBanner />}

      {mounted && isWhatsAppPopupOpen && messaggioCorrente && (
        <WhatsAppPopup
          messaggio={messaggioCorrente}
          onClose={closeWhatsAppPopup}
        />
      )}
    </Box>
  );
}